import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'Música' | 'Humor' | 'TikTok' | 'TV & Cinema' | 'Influencer';

export interface Artist {
  id: string;
  name: string;
  category: Category;
  priceKz: number;
  imageUrl: string;
  bio: string;
  rating: number;
  deliveryTimeDays: number;
}

export interface Order {
  id: string;
  artistId: string;
  artistName: string;
  from: string;
  to: string;
  occasion: string;
  instructions: string;
  contactEmail: string;
  status: 'Pendente' | 'Pago' | 'Concluido' | 'Cancelado';
  proofUrl?: string;
  priceKz: number;
  createdAt: number;
}

import React from 'react';

interface HeaderProps {
  onGoHome: () => void;
  onGoToDashboard: () => void;
  isDashboard?: boolean;
}

export const Header: React.FC<HeaderProps> = ({ onGoHome, onGoToDashboard, isDashboard }) => {
  return (
    <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800 px-4 py-4 flex items-center justify-between">
      <div 
        className="flex items-center gap-2 cursor-pointer" 
        onClick={onGoHome}
      >
        <span className="text-2xl font-black text-orange-500 tracking-tighter">KASSUMUNA</span>
      </div>

      <button 
        onClick={isDashboard ? onGoHome : onGoToDashboard}
        className="px-4 py-2 text-sm font-medium rounded-full border border-zinc-700 hover:bg-zinc-800 transition-colors"
      >
        {isDashboard ? 'Explorar' : 'Painel Artista'}
