import React, { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { ArtistCard } from './components/ArtistCard';
import { OrderForm } from './components/OrderForm';
import { CheckoutPage } from './components/CheckoutPage';
import { ArtistDashboard } from './components/ArtistDashboard';
import { ARTISTS } from './constants';
import { Artist, Order, Category } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'checkout' | 'dashboard' | 'success'>('home');
  const [selectedArtist, setSelectedArtist] = useState<Artist | null>(null);
  const [currentOrder, setCurrentOrder] = useState<any>(null);
  const [orders, setOrders] = useState<Order[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<Category | 'Todos'>('Todos');

  const categories: (Category | 'Todos')[] = ['Todos', 'Música', 'Humor', 'TikTok', 'Influencer'];

  const handleArtistClick = (artist: Artist) => {
    setSelectedArtist(artist);
  };

  const handleOrderSubmit = (orderData: any) => {
    setCurrentOrder(orderData);
    setView('checkout');
  };

  const handlePaymentConfirm = (proofUrl?: string) => {
    const newOrder: Order = {
      id: Math.random().toString(36).substr(2, 9),
      ...currentOrder,
      proofUrl,
      status: 'Pago'
    };
    setOrders([newOrder, ...orders]);
    setView('success');
  };

  const handleCompleteOrder = (orderId: string) => {
    setOrders(orders.filter(o => o.id !== orderId));
  };

  const filteredArtists = selectedCategory === 'Todos' 
    ? ARTISTS 
    : ARTISTS.filter(a => a.category === selectedCategory);

  return (
    <div className="min-h-screen pb-20 max-w-2xl mx-auto border-x border-zinc-900 bg-black">
      <Header 
        onGoHome={() => setView('home')} 
        onGoToDashboard={() => setView('dashboard')}
        isDashboard={view === 'dashboard'}
      />

      <main>
        {view === 'home' && (
          <div className="p-4 space-y-8 animate-in fade-in duration-500">
            {/* Hero Section */}
            <section className="py-6">
              <h1 className="text-4xl font-black text-white leading-tight tracking-tighter mb-2">
                Vídeos <span className="text-orange-500">Exclusivos</span> das tuas Estrelas.
              </h1>
              <p className="text-zinc-400 text-lg">
                Pede saudações, parabéns e piadas personalizadas.
              </p>
            </section>

            {/* Categories */}
            <div className="flex gap-2 overflow-x-auto pb-2 no-scrollbar">
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-4 py-2 rounded-full text-sm font-bold whitespace-nowrap transition-all ${
                    selectedCategory === cat 
                      ? 'bg-orange-500 text-white' 
                      : 'bg-zinc-900 text-zinc-400 hover:bg-zinc-800'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>

            {/* Artist Grid */}
            <div className="grid grid-cols-2 gap-4">
              {filteredArtists.map(artist => (
                <ArtistCard 
                  key={artist.id} 
                  artist={artist} 
                  onClick={handleArtistClick} 
                />
              ))}
            </div>
          </div>
        )}

        {view === 'checkout' && currentOrder && (
          <CheckoutPage 
            order={currentOrder} 
            onBack={() => setView('home')} 
            onConfirm={handlePaymentConfirm} 
          />
        )}

        {view === 'dashboard' && (
          <ArtistDashboard 
            orders={orders} 
            onCompleteOrder={handleCompleteOrder} 
          />
        )}

        {view === 'success' && (
          <div className="p-8 text-center space-y-6 pt-20 animate-in zoom-in duration-300">
            <div className="w-24 h-24 bg-green-500/20 text-green-500 rounded-full flex items-center justify-center mx-auto">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" />
              </svg>
            </div>
            <h2 className="text-3xl font-bold">Pedido Enviado!</h2>
            <p className="text-zinc-400">
              O comprovativo está em validação. Receberás o vídeo no teu contacto em até 5 dias úteis.
            </p>
            <button 
              onClick={() => setView('home')}
              className="w-full bg-zinc-900 border border-zinc-800 text-white font-bold py-4 rounded-xl hover:bg-zinc-800 transition-colors"
            >
              Voltar ao Início
            </button>
          </div>
        )}
      </main>

      {/* Artist Profile / Order Form Modal */}
      {selectedArtist && view === 'home' && (
        <OrderForm 
          artist={selectedArtist} 
          onCancel={() => setSelectedArtist(null)}
          onSubmit={(data) => {
            setSelectedArtist(null);
            handleOrderSubmit(data);
          }}
        />
      )}

      {/* Floating Bottom Navigation for Mobile */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-2xl mx-auto bg-zinc-950/80 backdrop-blur-lg border-t border-zinc-900 p-3 flex justify-around items-center z-50">
        <button onClick={() => setView('home')} className={`flex flex-col items-center gap-1 ${view === 'home' ? 'text-orange-500' : 'text-zinc-500'}`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" />
          </svg>
          <span className="text-[10px] font-bold">Início</span>
        </button>
        <button onClick={() => setView('dashboard')} className={`flex flex-col items-center gap-1 ${view === 'dashboard' ? 'text-orange-500' : 'text-zinc-500'}`}>
          <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
          </svg>
          <span className="text-[10px] font-bold">Perfil</span>
        </button>
      </nav>
    </div>
  );
};

export default App;

import { Order, Artist } from '../types';
import { ARTISTS as MOCK_ARTISTS } from '../constants';

const ORDERS_KEY = 'kassumuna_orders';

export const StorageService = {
  getArtists: (): Artist[] => {
    return MOCK_ARTISTS;
  },

  getOrders: (): Order[] => {
    const data = localStorage.getItem(ORDERS_KEY);
    return data ? JSON.parse(data) : [];
  },

  saveOrder: (order: Order): void => {
    const orders = StorageService.getOrders();
    const updatedOrders = [order, ...orders];
    localStorage.setItem(ORDERS_KEY, JSON.stringify(updatedOrders));
  },

  updateOrderStatus: (orderId: string, status: Order['status']): void => {
    const orders = StorageService.getOrders();
    const updatedOrders = orders.map(o => o.id === orderId ? { ...o, status } : o);
    localStorage.setItem(ORDERS_KEY, JSON.stringify(updatedOrders));
  },

  deleteOrder: (orderId: string): void => {
    const orders = StorageService.getOrders();
    const updatedOrders = orders.filter(o => o.id !== orderId);
    localStorage.setItem(ORDERS_KEY, JSON.stringify(updatedOrders));
  }
};

